const raw   = items[0].json;
const input = raw.body || raw;

const pdfBase64       = input.pdf_base64       || null;
const texSource       = input.tex_source       || '';
const atsScore        = typeof input.ats_score === 'number' ? input.ats_score : null;
const matchedKeywords = Array.isArray(input.matched_keywords) ? input.matched_keywords : [];
const compileError    = input.compile_error    || null;

return [{
  json: {
    pdf_base64:       pdfBase64,
    tex_source:       texSource,
    ats_score:        atsScore,
    matched_keywords: matchedKeywords,
    compile_error:    compileError,
    generated_at:     new Date().toISOString(),
    status:           pdfBase64 ? 'success' : 'partial'
  }
}];
